import React, { createContext, useCallback, useContext, useEffect, useMemo, useReducer, useRef } from "react";
import { ActivityIndicator, Alert, Button, SafeAreaView, Text, TextInput, View } from "react-native";
import AsyncStorage from "@react-native-async-storage/async-storage";
import { NavigationContainer } from "@react-navigation/native";
import { createNativeStackNavigator } from "@react-navigation/native-stack";

const AUTH_STORAGE_KEY = "@mvp_auth_v1";

async function apiLogin({ email, password }) {
  await new Promise((r) => setTimeout(r, 600));
  if (!email || !password) throw new Error("Email and password are required.");
  if (password.length < 4) throw new Error("Invalid credentials.");
  return {
    token: "demo_token_" + Math.random().toString(36).slice(2),
    user: {
      id: "u_" + Math.random().toString(36).slice(2),
      email,
      name: email.split("@")[0] || "User",
    },
  };
}

async function apiMe(token) {
  await new Promise((r) => setTimeout(r, 300));
  if (!token) throw new Error("Missing token");
  return {
    id: "u_persisted",
    email: "persisted@example.com",
    name: "Persisted User",
  };
}

function safeJsonParse(str) {
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

const AuthContext = createContext(null);

const initialState = {
  isBootstrapping: true,
  token: null,
  user: null,
};

function reducer(state, action) {
  switch (action.type) {
    case "BOOTSTRAP_START":
      return { ...state, isBootstrapping: true };
    case "BOOTSTRAP_DONE":
      return { ...state, isBootstrapping: false, token: action.token, user: action.user };
    case "SIGN_IN":
      return { ...state, token: action.token, user: action.user };
    case "SIGN_OUT":
      return { ...state, token: null, user: null };
    case "SET_USER":
      return { ...state, user: action.user };
    default:
      return state;
  }
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(reducer, initialState);
  const bootstrapInFlight = useRef(false);

  const persistAuth = useCallback(async ({ token, user }) => {
    const payload = JSON.stringify({
      token,
      user,
      savedAt: Date.now(),
    });
    await AsyncStorage.setItem(AUTH_STORAGE_KEY, payload);
  }, []);

  const clearPersistedAuth = useCallback(async () => {
    await AsyncStorage.removeItem(AUTH_STORAGE_KEY);
  }, []);

  const bootstrap = useCallback(async () => {
    if (bootstrapInFlight.current) return;
    bootstrapInFlight.current = true;
    dispatch({ type: "BOOTSTRAP_START" });

    try {
      const raw = await AsyncStorage.getItem(AUTH_STORAGE_KEY);
      const parsed = raw ? safeJsonParse(raw) : null;

      if (parsed?.token) {
        let user = parsed.user || null;
        try {
          user = await apiMe(parsed.token);
        } catch {
          await clearPersistedAuth();
          dispatch({ type: "BOOTSTRAP_DONE", token: null, user: null });
          return;
        }
        dispatch({ type: "BOOTSTRAP_DONE", token: parsed.token, user });
      } else {
        dispatch({ type: "BOOTSTRAP_DONE", token: null, user: null });
      }
    } catch {
      dispatch({ type: "BOOTSTRAP_DONE", token: null, user: null });
    } finally {
      bootstrapInFlight.current = false;
    }
  }, [clearPersistedAuth]);

  useEffect(() => {
    bootstrap();
  }, [bootstrap]);

  const signIn = useCallback(
    async ({ email, password }) => {
      const res = await apiLogin({ email, password });
      dispatch({ type: "SIGN_IN", token: res.token, user: res.user });
      await persistAuth({ token: res.token, user: res.user });
      return res;
    },
    [persistAuth]
  );

  const signOut = useCallback(async () => {
    dispatch({ type: "SIGN_OUT" });
    await clearPersistedAuth();
  }, [clearPersistedAuth]);

  const updateUser = useCallback(
    async (user) => {
      dispatch({ type: "SET_USER", user });
      if (state.token) await persistAuth({ token: state.token, user });
    },
    [persistAuth, state.token]
  );

  const value = useMemo(
    () => ({
      isBootstrapping: state.isBootstrapping,
      token: state.token,
      user: state.user,
      isAuthenticated: !!state.token,
      signIn,
      signOut,
      updateUser,
      refresh: bootstrap,
    }),
    [state.isBootstrapping, state.token, state.user, signIn, signOut, updateUser, bootstrap]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error("useAuth must be used within AuthProvider");
  return ctx;
}

const AuthStack = createNativeStackNavigator();
const AppStack = createNativeStackNavigator();

function SplashScreen() {
  return (
    <SafeAreaView style={{ flex: 1, alignItems: "center", justifyContent: "center" }}>
      <ActivityIndicator size="large" />
      <Text style={{ marginTop: 12 }}>Loading...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = React.useState("");
  const [password, setPassword] = React.useState("");
  const [loading, setLoading] = React.useState(false);

  const onSubmit = async () => {
    setLoading(true);
    try {
      await signIn({ email: email.trim(), password });
    } catch (e) {
      Alert.alert("Login failed", e?.message || "Unknown error");
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={{ flex: 1, padding: 16, gap: 12 }}>
      <Text style={{ fontSize: 24, fontWeight: "600" }}>Sign In</Text>

      <View style={{ gap: 6 }}>
        <Text>Email</Text>
        <TextInput
          autoCapitalize="none"
          autoCorrect={false}
          keyboardType="email-address"
          value={email}
          onChangeText={setEmail}
          placeholder="you@example.com"
          style={{
            borderWidth: 1,
            borderColor: "#ccc",
            borderRadius: 8,
            paddingHorizontal: 12,
            paddingVertical: 10,
          }}
        />
      </View>

      <View style={{ gap: 6 }}>
        <Text>Password</Text>
        <TextInput
          secureTextEntry
          value={password}
          onChangeText={setPassword}
          placeholder="••••"
          style={{
            borderWidth: 1,
            borderColor: "#ccc",
            borderRadius: 8,
            paddingHorizontal: 12,
            paddingVertical: 10,
          }}
        />
      </View>

      <View style={{ marginTop: 8 }}>
        <Button title={loading ? "Signing in..." : "Sign In"} onPress={onSubmit} disabled={loading} />
      </View>

      <Text style={{ color: "#666", marginTop: 8 }}>
        Demo: any email + password length ≥ 4
      </Text>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, signOut, updateUser } = useAuth();

  const changeName = async () => {
    const next = { ...(user || {}), name: (user?.name || "User") + "!" };
    await updateUser(next);
  };

  return (
    <SafeAreaView style={{ flex: 1, padding: 16, gap: 12 }}>
      <Text style={{ fontSize: 24, fontWeight: "600" }}>Home</Text>

      <View style={{ padding: 12, borderWidth: 1, borderColor: "#ddd", borderRadius: 10, gap: 6 }}>
        <Text style={{ fontWeight: "600" }}>User</Text>
        <Text>ID: {user?.id || "-"}</Text>
        <Text>Name: {user?.name || "-"}</Text>
        <Text>Email: {user?.email || "-"}</Text>
      </View>

      <View style={{ padding: 12, borderWidth: 1, borderColor: "#ddd", borderRadius: 10, gap: 6 }}>
        <Text style={{ fontWeight: "600" }}>Token</Text>
        <Text numberOfLines={1} ellipsizeMode="middle">
          {token || "-"}
        </Text>
      </View>

      <View style={{ gap: 10, marginTop: 6 }}>
        <Button title="Update user name (persist)" onPress={changeName} />
        <Button title="Sign Out" onPress={signOut} color="#b00020" />
      </View>
    </SafeAreaView>
  );
}

function AuthNavigator() {
  return (
    <AuthStack.Navigator>
      <AuthStack.Screen name="Login" component={LoginScreen} options={{ title: "Sign In" }} />
    </AuthStack.Navigator>
  );
}

function AppNavigator() {
  return (
    <AppStack.Navigator>
      <AppStack.Screen name="Home" component={HomeScreen} options={{ title: "MVP" }} />
    </AppStack.Navigator>
  );
}

function RootNavigator() {
  const { isBootstrapping, isAuthenticated } = useAuth();

  if (isBootstrapping) return <SplashScreen />;

  return isAuthenticated ? <AppNavigator /> : <AuthNavigator />;
}

export default function App() {
  return (
    <AuthProvider>
      <NavigationContainer>
        <RootNavigator />
      </NavigationContainer>
    </AuthProvider>
  );
}